breakdown:[{t:"# comment",n:"Lines starting with <b>#</b> are comments — Python ignores them entirely."},{t:"print(\"Hello\")",n:"<b>print()</b> displays whatever is inside the parentheses on screen."},{t:"\"Hello, World!\"",n:"A <b>string</b> — text wrapped in double quotes. Single quotes also work."},{t:"print(42)",n:"Numbers don't need quotes. Python knows 42 is a number, not text."},{t:"print(10 + 5)",n:"Python evaluates math first, then prints the result — here it prints 15."}],
