concepts:[{i:"📰",t:"h1 to h6",d:"Six heading sizes — h1 is biggest, h6 smallest."},{i:"📄",t:"&lt;p&gt;",d:"Paragraph — basic block of text. Browsers add spacing above/below."},{i:"💪",t:"&lt;strong&gt;",d:"Bold text — also marks content as important."},{i:"✨",t:"&lt;em&gt;",d:"Italic text — marks emphasis."}],
