concepts:[{i:"⚙️",t:"Compiled",d:"C++ code is converted to machine code before running."},{i:"📦",t:"#include",d:"Import a library of pre-built code."},{i:"🚪",t:"main()",d:"Entry point — every C++ program starts here."},{i:"📣",t:"cout",d:"Console output — stream data to screen with << operator."}],
