code:["#include <iostream>","#include <vector>","#include <algorithm>","using namespace std;","","int main() {","    int scores[5] = {90, 85, 78, 92, 88};","    cout << scores[0] << endl;","","    vector<string> fruits = {\"apple\",\"banana\",\"mango\"};","    fruits.push_back(\"kiwi\");","    fruits.pop_back();","    cout << \"Size: \" << fruits.size() << endl;","","    for (auto& fruit : fruits) {","        cout << fruit << endl;","    }","","    vector<int> nums = {5, 2, 8, 1, 9};","    sort(nums.begin(), nums.end());","    for (auto n : nums) cout << n << \" \";","    cout << endl;","","    return 0;","}"],
