code:["#include <iostream>","#include <string>","using namespace std;","","class Animal {","public:","    string name;","    int    age;","","    Animal(string n, int a) : name(n), age(a) {}","","    void speak() {","        cout << name << \" makes a sound.\" << endl;","    }","","    virtual string sound() { return \"...\"; }","};","","class Dog : public Animal {","public:","    Dog(string n, int a) : Animal(n, a) {}","","    string sound() override { return \"Woof\"; }","","    void fetch() {","        cout << name << \" fetches the ball!\" << endl;","    }","};","","int main() {","    Dog rex(\"Rex\", 3);","    rex.speak();","    cout << rex.sound() << endl;","    rex.fetch();","    return 0;","}"],
